scwin.vAuthYn = "N";
scwin.privAdmin = "";
scwin.g_sUserId = "";
scwin.total = [];
scwin.stdRamtSum = [];
scwin.stdYm = "";
scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "ZZ006",
    compID: "lc_crcCd,lc_ramtCrcCd,gr_additionalValue:crcCd"
  }, {
    grpCd: "IL111",
    compID: "gr_additionalValue:gubun",
    opt: {
      "range": "1,1"
    }
  }, {
    grpCd: "IL112",
    compID: "gr_additionalValue:additionalKndCd"
  }];
  $c.data.setCommonCode($p, codeOptions, scwin.callbackCode);
  btn_fieldClear.hide();
  var params = $c.data.getParameter($p);
  scwin.stdYm = params.stdYm == null ? "" : params.stdYm;
  let memJson = $c.data.getMemInfo($p);
  console.log(memJson);
  scwin.privAdmin = memJson.privAdmin;
  scwin.g_sUserId = memJson.empNo;
};
scwin.onUdcCompleted = function () {
  $p.setTimeout(function () {
    ica_stdYm.setValue(scwin.strStdDt);
    lc_crcCd.setValue("USD");
    scwin.f_getRamt();
    scwin.f_retrieveAuth();
    $c.gus.cfDisableObjects($p, [ica_recvMagamDt, ica_paymentMagamDt]);
    if (scwin.stdYm.trim() != "") {
      ica_stdYm.setValue(scwin.stdYm);
      //dma_search.set("crcCd","USD");
      scwin.f_Retrieve();
      $c.gus.cfDisableObjects($p, [btn_save, btn_saveAdditionalValue, btn_paymentDtsave]);
    }
  }, {
    "delay": 300
  });
};
scwin.callbackCode = function () {
  ica_stdYm.setValue(scwin.strStdDt);
  lc_ramtCrcCd.addItem("전체", "", null, 0);
  lc_ramtCrcCd.setValue("USD");
  lc_crcCd.addItem("전체", "", null, 0);
  lc_crcCd.setValue("USD");
  console.log("lc_crcCd.getValue() : " + lc_crcCd.getValue());
  console.log("dma_search.get('crcCd') : " + JSON.stringify(dma_search.getJSON()));
};

