//조회
scwin.f_Retrieve = async function () {
  var chk = await $c.gus.cfValidate($p, [ica_stdYm]);
  if (!chk) {
    return false;
  }
  lc_ramtCrcCd.setValue(lc_crcCd.getValue());
  await scwin.f_getRamt();
  await scwin.f_getRecvMagam(); //확정일자
  await scwin.f_getPaymentMagam(); //확정일자

  $p.setTimeout(function () {
    chk = ica_recvMagamDt.getValue() == "" || ica_paymentMagamDt.getValue() == "";
    if (chk) {
      $c.win.alert($p, "계획 확정 전으로 조회가 불가합니다");
      return;
    } else {
      $c.sbm.execute($p, sbm_retrieve);
      $c.sbm.execute($p, sbm_retrievePaymentDt);
      $c.sbm.execute($p, sbm_retrieveAdditionalValue);
    }
  }, {
    "delay": 400
  });
};

