scwin.sbm_retrieve_submitdone = async function (e) {
  var rowcnt = ds_masterList.getRowCount();
  if (rowcnt == 0) {
    $c.win.alert($p, E_MSG_CM_WRN_002);
  } else {
    await scwin.f_addSum();
    scwin.getLastDayOfMonth();
  }
};
scwin.sbm_saveAdditionalValue_submitdone = function (e) {
  console.log(e.responseJSON.resultDataSet);
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    $c.win.alert($p, "추가값이 저장되었습니다."); // 성공적으로 저장하였습니다
    scwin.f_Retrieve();
  } else {
    if (e.responseJSON.resultDataSet[1] != null && e.responseJSON.resultDataSet[1].Msg != null && e.responseJSON.resultDataSet[1].Msg != "") {
      $c.win.alert($p, e.responseJSON.resultDataSet[1].Msg);
    }
  }
};
