scwin.gr_paymentDt_oncellclick = function (row, columnIndex, columnId) {
  if (scwin.vAuthYn == "Y") {
    if (ds_paymentDt.getRowStatus(row) == "C") {
      //gr_paymentDt.ColumnProp("paymentDt","Edit") = "ANY";
      gr_paymentDt.setCellReadOnly(row, "paymentDt", false);
    } else {
      //gr_paymentDt.ColumnProp("paymentDt","Edit") = "None";
      gr_paymentDt.setCellReadOnly(row, "paymentDt", true);
    }
  } else {
    //gr_paymentDt.ColumnProp("paymentDt","Edit") = "None";
    gr_paymentDt.setCellReadOnly(row, "paymentDt", true);
  }
};
scwin.gr_additionalValue_oncellclick = function (row, columnIndex, colid) {
  if (ds_additionalValue.getRowStatus(row) == "C") {
    /*
    gr_additionalValue.ColumnProp("additionalKndCd","Edit") = "ANY";
    gr_additionalValue.ColumnProp("crcCd","Edit") = "ANY";
    gr_additionalValue.ColumnProp("stdDt","Edit") = "ANY";
    */
    gr_additionalValue.setCellReadOnly(row, "additionalKndCd", false);
    gr_additionalValue.setCellReadOnly(row, "crcCd", false);
    gr_additionalValue.setCellReadOnly(row, "stdDt", false);
  } else {
    /*
    gr_additionalValue.ColumnProp("additionalKndCd","Edit") = "None";
    gr_additionalValue.ColumnProp("crcCd","Edit") = "None";
    gr_additionalValue.ColumnProp("stdDt","Edit") = "ANY";
    */
    gr_additionalValue.setCellReadOnly(row, "additionalKndCd", true);
    gr_additionalValue.setCellReadOnly(row, "crcCd", true);
    gr_additionalValue.setCellReadOnly(row, "stdDt", false);
  }
  if (colid == "additionalKndCd") {
    if (ds_additionalValue.getCellData(row, "gubun") == "1") {} else {}
  }
};
scwin.ds_additionalValue_oncelldatachange = function (info) {
  // {realRowIndex: 2, rowIndex: 2, colID: 'leng', oldValue: '4', newValue: '5'}
  var colid = info.colID;
  var row = info.rowIndex;
  console.log("colid :" + colid);
  if (colid == "additionalKndCd") {
    console.log(ds_additionalValue.getCellData(row, "additionalKndCd"));
    if (ds_additionalValue.getCellData(row, "additionalKndCd") == "1" || ds_additionalValue.getCellData(row, "additionalKndCd") == "2" || ds_additionalValue.getCellData(row, "additionalKndCd") == "3") {
      ds_additionalValue.setCellData(row, "gubun", "1");
    } else if (ds_additionalValue.getCellData(row, "additionalKndCd") == "4" || ds_additionalValue.getCellData(row, "additionalKndCd") == "5") {
      ds_additionalValue.setCellData(row, "gubun", "2");
    }
  }
};
